"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { Plus, Check } from 'lucide-react';

const DAYS = ['L', 'M', 'M', 'J', 'V', 'S', 'D'];
const DAY_NAMES = ['Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado', 'Domingo'];

const Habitos: React.FC = () => {
  const { state, toggleHabitDay, addHabit } = useJournal();
  const [newName, setNewName] = useState('');
  const [newEmoji, setNewEmoji] = useState('✨');

  const handleAdd = (e: React.FormEvent) => {
    e.preventDefault();
    if (newName.trim()) {
      addHabit(newName, newEmoji);
      setNewName('');
    }
  };

  return (
    <div className="space-y-6 max-w-4xl mx-auto pb-20 px-2">
      <header className="border-b border-rose-pastel pb-4 px-2">
        <h2 className="text-3xl font-serif text-soft-text font-light italic">Hábitos</h2>
        <p className="text-soft-text/60 text-xs font-bold uppercase tracking-widest">Tu progreso semanal</p>
      </header>

      {/* VISTA MÓVIL: Tarjetas (Se ve en pantallas pequeñas) */}
      <div className="block md:hidden space-y-4">
        {state.habits.map((habit) => (
          <div key={habit.id} className="bg-white p-5 rounded-[2rem] journal-shadow border border-rose-pastel/50">
            <div className="flex justify-between items-center mb-4">
              <div className="flex items-center gap-3">
                <span className="text-2xl">{habit.emoji}</span>
                <span className="font-bold text-soft-text">{habit.name}</span>
              </div>
              <span className="bg-rose-pastel text-deep-rose px-3 py-1 rounded-full text-xs font-bold">
                {habit.completedDays.filter(Boolean).length}/7
              </span>
            </div>
            <div className="grid grid-cols-7 gap-1">
              {habit.completedDays.map((completed, idx) => (
                <div key={idx} className="flex flex-col items-center gap-1">
                  <span className="text-[10px] text-soft-text/40 font-bold">{DAYS[idx]}</span>
                  <button
                    onClick={() => toggleHabitDay(habit.id, idx)}
                    className={`w-10 h-10 rounded-full flex items-center justify-center border-2 transition-all
                      ${completed ? 'bg-accent-pink border-accent-pink text-white' : 'border-rose-pastel/30'}`}
                  >
                    {completed && <Check size={16} />}
                  </button>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>

      {/* VISTA DESKTOP: Tabla (Se oculta en móvil) */}
      <div className="hidden md:block bg-white rounded-[2.5rem] journal-shadow border border-rose-pastel/30 overflow-hidden">
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-rose-pastel/20">
              <th className="p-6 text-deep-rose font-bold uppercase text-xs tracking-widest">Hábito</th>
              {DAYS.map((day, i) => (
                <th key={i} className="p-6 text-center text-soft-text/40 text-xs font-bold">{day}</th>
              ))}
              <th className="p-6 text-center text-deep-rose font-bold uppercase text-xs tracking-widest">Total</th>
            </tr>
          </thead>
          <tbody>
            {state.habits.map((habit) => (
              <tr key={habit.id} className="border-t border-rose-pastel/10 hover:bg-lavender-pastel/5 transition-colors">
                <td className="p-6">
                  <div className="flex items-center gap-3">
                    <span className="text-2xl">{habit.emoji}</span>
                    <span className="font-medium text-soft-text">{habit.name}</span>
                  </div>
                </td>
                {habit.completedDays.map((completed, dayIdx) => (
                  <td key={dayIdx} className="p-4 text-center">
                    <button
                      onClick={() => toggleHabitDay(habit.id, dayIdx)}
                      className={`w-10 h-10 rounded-full inline-flex items-center justify-center border-2 transition-all
                        ${completed ? 'bg-accent-pink border-accent-pink text-white scale-110' : 'border-rose-pastel/30 hover:border-accent-pink'}`}
                    >
                      {completed && <Check size={16} />}
                    </button>
                  </td>
                ))}
                <td className="p-6 text-center">
                  <span className="bg-lavender-pastel text-deep-rose px-4 py-2 rounded-full text-sm font-bold">
                    {habit.completedDays.filter(Boolean).length}/7
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Formulario de añadir - Ajustado para móvil */}
      <form onSubmit={handleAdd} className="flex flex-col sm:flex-row gap-3 bg-white p-4 rounded-[2rem] journal-shadow border border-rose-pastel/30">
        <div className="flex gap-2 flex-1">
          <input
            type="text"
            value={newEmoji}
            onChange={(e) => setNewEmoji(e.target.value)}
            className="w-14 text-center bg-rose-pastel/20 rounded-2xl p-3 text-xl"
            placeholder="✨"
          />
          <input
            type="text"
            value={newName}
            onChange={(e) => setNewName(e.target.value)}
            placeholder="Nuevo hábito..."
            className="flex-1 bg-transparent border-none outline-none text-soft-text font-medium px-2"
          />
        </div>
        <button type="submit" className="bg-accent-pink text-white px-8 py-4 rounded-2xl hover:bg-deep-rose transition-all font-bold shadow-lg shadow-accent-pink/20">
          Añadir Hábito
        </button>
      </form>
    </div>
  );
};

export default Habitos;
