"use client";
import React, { useState } from 'react';
import { useJournal } from '../context/JournalContext';
import { CheckCircle2, Circle, Plus, Heart, Sparkles, Flame } from 'lucide-react';
import { motion } from 'framer-motion';
import { Mood } from '../types';

const MOODS: { emoji: string; label: Mood }[] = [
  { emoji: '😢', label: 'triste' },
  { emoji: '😐', label: 'neutral' },
  { emoji: '🙂', label: 'bien' },
  { emoji: '😊', label: 'feliz' },
  { emoji: '🤩', label: 'genial' },
];

const Hoy: React.FC = () => {
  const { state, updateToday } = useJournal();
  const { today, streak } = state;
  const [newTask, setNewTask] = useState('');

  const addTask = () => {
    if (!newTask.trim()) return;
    const task = { id: Date.now().toString(), text: newTask, completed: false };
    updateToday({ tasks: [...today.tasks, task] });
    setNewTask('');
  };

  const selectedMoodEmoji = MOODS.find(m => m.label === today.mood)?.emoji;

  return (
    <div className="space-y-8 max-w-2xl mx-auto pb-20 px-2 sm:px-4">
      <header className="flex flex-col gap-6">
        <div className="flex justify-between items-start">
          <div>
            <h2 className="text-3xl sm:text-4xl font-serif text-soft-text font-light italic leading-tight">Hola, Abigail</h2>
            <div className="flex items-center gap-2 mt-1">
              <p className="text-deep-rose font-medium text-xs sm:text-sm tracking-wide">
                {new Date().toLocaleDateString('es-ES', { weekday: 'long', day: 'numeric', month: 'long' })}
              </p>
              <div className="flex items-center gap-1 bg-orange-100 text-orange-600 px-2 py-0.5 rounded-full text-[10px] sm:text-xs font-bold">
                <Flame size={10} fill="currentColor" />
                <span>{streak} días</span>
              </div>
            </div>
          </div>
          
          {/* Indicador de ánimo actual - Si ya se eligió */}
          {today.mood && (
            <motion.div 
              initial={{ scale: 0 }} animate={{ scale: 1 }}
              className="bg-white p-3 rounded-2xl shadow-sm border border-rose-pastel flex items-center gap-2"
            >
              <span className="text-2xl">{selectedMoodEmoji}</span>
              <span className="text-[10px] uppercase font-bold text-soft-text/40 hidden sm:block">Hoy</span>
            </motion.div>
          )}
        </div>

        {/* Selector de ánimo: Solo se ve si NO hay ánimo seleccionado */}
        {!today.mood && (
          <div className="bg-white/40 backdrop-blur-sm p-4 rounded-[2rem] border border-rose-pastel">
            <p className="text-[10px] uppercase tracking-widest font-bold text-soft-text/40 mb-3 text-center">¿Cómo te sientes en este momento?</p>
            <div className="flex justify-around gap-2">
              {MOODS.map((m) => (
                <button
                  key={m.label}
                  onClick={() => updateToday({ mood: m.label })}
                  className="text-2xl p-3 rounded-2xl transition-all duration-300 hover:bg-white/60"
                  title={m.label || ''}
                >
                  {m.emoji}
                </button>
              ))}
            </div>
          </div>
        )}
      </header>

      {/* Prioridades */}
      <section className="bg-white p-6 sm:p-8 rounded-[2rem] journal-shadow border border-rose-pastel/50">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-xs uppercase tracking-widest">
          <Sparkles size={14} />
          <h3>Prioridades</h3>
        </div>
        <div className="space-y-3">
          {today.priorities.map((p, i) => (
            <input
              key={i}
              type="text"
              value={p}
              onChange={(e) => {
                const newP = [...today.priorities];
                newP[i] = e.target.value;
                updateToday({ priorities: newP });
              }}
              placeholder={`Prioridad ${i+1}...`}
              className="w-full bg-rose-pastel/10 border-none rounded-xl px-4 py-3 outline-none focus:bg-rose-pastel/20 transition-all text-soft-text text-sm"
            />
          ))}
        </div>
      </section>

      {/* Tareas */}
      <section className="bg-white p-6 sm:p-8 rounded-[2.5rem] journal-shadow border border-rose-pastel/50">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-xs uppercase tracking-widest">
          <CheckCircle2 size={14} />
          <h3>Cosas por hacer</h3>
        </div>
        <div className="space-y-4 mb-8">
          {today.tasks.length === 0 && <p className="text-soft-text/30 italic text-sm text-center py-4">No hay tareas pendientes...</p>}
          {today.tasks.map((task) => (
            <div key={task.id} className="flex items-center gap-4 group cursor-pointer" onClick={() => {
              updateToday({ tasks: today.tasks.map(t => t.id === task.id ? { ...t, completed: !t.completed } : t) });
            }}>
              <div className={`text-accent-pink transition-all ${task.completed ? 'scale-90' : 'group-hover:scale-110'}`}>
                {task.completed ? <CheckCircle2 size={22} fill="#fbcfe8" className="text-white" /> : <Circle size={22} className="opacity-40" />}
              </div>
              <span className={`flex-1 text-sm ${task.completed ? 'line-through text-soft-text/30' : 'text-soft-text'}`}>
                {task.text}
              </span>
            </div>
          ))}
        </div>
        <div className="flex gap-2 bg-lavender-pastel/20 p-2 rounded-2xl">
          <input
            type="text"
            value={newTask}
            onChange={(e) => setNewTask(e.target.value)}
            onKeyPress={(e) => e.key === 'Enter' && addTask()}
            placeholder="Nueva tarea..."
            className="flex-1 bg-transparent border-none px-3 py-2 outline-none text-soft-text text-sm"
          />
          <button onClick={addTask} className="bg-accent-pink text-white p-2.5 rounded-xl hover:bg-deep-rose">
            <Plus size={18} />
          </button>
        </div>
      </section>

      {/* Agradecimientos */}
      <section className="bg-gradient-to-br from-rose-pastel/60 to-lavender-pastel/60 p-6 sm:p-8 rounded-[2.5rem] border border-white shadow-sm">
        <div className="flex items-center gap-2 mb-6 text-deep-rose font-bold text-xs uppercase tracking-widest">
          <Heart size={14} fill="#fbcfe8" className="text-accent-pink" />
          <h3>Hoy agradezco por...</h3>
        </div>
        <div className="space-y-3">
          {today.gratitude.map((g, i) => (
            <input
              key={i}
              type="text"
              value={g}
              onChange={(e) => {
                const newG = [...today.gratitude];
                newG[i] = e.target.value;
                updateToday({ gratitude: newG });
              }}
              placeholder={`Agradecimiento ${i+1}...`}
              className="w-full bg-white/40 backdrop-blur-sm border-none rounded-xl px-4 py-3 outline-none focus:bg-white transition-all text-soft-text text-sm italic"
            />
          ))}
        </div>
      </section>
    </div>
  );
};

export default Hoy;
